const fetchCallData = async () => {
  try {
    // Get call data from history endpoint which includes transcription
    const response = await axios.get(`${apiUrl}/calls/history?limit=200`);
    const calls = response.data.calls || response.data;

    // Find the specific call by ID
    const call = calls.find(c =>
      c.id === parseInt(callId) ||
      c.call_uuid === callId ||
      c.id === callId
    );

    if (call) {
      setCallData(call);

      // Parse the transcription if it exists
      if (call.transcription_text) {
        const lines = call.transcription_text.split('\n');
        const conversation = lines.map((line, index) => {
          const isAgent = line.startsWith('Agent:');
          const isCustomer = line.startsWith('Customer:');
          return {
            speaker: isAgent ? 'Agent' : isCustomer ? 'Customer' : 'System',
            text: line.replace(/^(Agent:|Customer:)\s*/, ''),
            timestamp: `${Math.floor(index * 2 / 60)}:${String((index * 2) % 60).padStart(2, '0')}`
          };
        }).filter(item => item.text.trim()); // Filter out empty lines

        setTranscript({
          conversation: conversation,
          keywords: [],
          sentiment: 'neutral',
          summary: `Call with ${call.phone_number} - ${conversation.length} exchanges`
        });
      }
