input.new_string:
const fetchCallDetails = async () => {
  setLoading(true);
  try {
    // Fetch all calls from history endpoint
    const response = await axios.get(`${apiUrl}/calls/history?limit=1000`);
    const calls = response.data.calls || response.data;

    // Find the specific call by ID
    const call = calls.find(c =>
      c.id === parseInt(callId) ||
      c.call_uuid === callId ||
      c.id?.toString() === callId
    );

    if (call) {
      // Set call data
      setCallData({
        id: call.id,
        uuid: call.call_uuid,
        phone_number: call.phone_number,
        lead_id: call.lead_id,
        lead_name: call.first_name ? `${call.first_name} ${call.last_name || ''}`.trim() : 'Unknown',
        lead_email: call.email,
        lead_company: call.company || call.business_name,
        campaign_name: call.campaign_name || 'Unknown Campaign',
        campaign_id: call.campaign_id,
        start_time: call.start_time,
        end_time: call.end_time,
        duration: call.duration_seconds || call.duration,
        status: call.call_status || call.status,
        disposition: call.disposition_code || call.disposition,
        bot_port: call.bot_port,
        agent_name: 'Ava',
        notes: call.notes || null,
        callback_scheduled: call.callback_datetime
      });

      // Parse and set transcript if available
      if (call.transcription_text) {
        const lines = call.transcription_text.split('\n');
        const conversation = [];

        lines.forEach((line, index) => {
          if (line.trim()) {
            const isAgent = line.startsWith('Agent:');
            const isCustomer = line.startsWith('Customer:');

            if (isAgent || isCustomer) {
              conversation.push({
                speaker: isAgent ? 'Agent' : 'Customer',
                text: line.replace(/^(Agent:|Customer:)\s*/, '').trim(),
                timestamp: '' // We don't have timestamps in the current format
              });
            }
          }
        });

        setTranscript({
          conversation: conversation,
          summary: null, // Could add AI summary later
          sentiment: null,
          keywords: []
        });
      } else {
        setTranscript(null);
      }

      // Set recording URL if available
      if (call.recording_url) {
        setRecording({
          url: call.recording_url,
          duration: call.duration_seconds || call.duration
        });
      } else {
        setRecording(null);
      }
    } else {
      // Call not found in history
      console.error('Call not found:', callId);
      // Use mock data as fallback
      setCallData({
        id: callId,
        uuid: `call-${callId}`,
        phone_number: 'Call not found',
        lead_name: 'Unknown',
        campaign_name: 'Unknown',
        start_time: new Date().toISOString(),
        duration: 0,
        status: 'unknown',
        disposition: 'NONE'
      });
      setTranscript(null);
      setRecording(null);
    }
  } catch (error) {
    console.error('Failed to fetch call details:', error);
    // If API fails, show error state
    setCallData({
      id: callId,
      uuid: `call-${callId}`,
      phone_number: 'Error loading data',
      lead_name: 'API Error',
      campaign_name: error.message,
      start_time: new Date().toISOString(),
      duration: 0,
      status: 'error',
      disposition: 'ERROR'
    });
    setTranscript(null);
    setRecording(null);
  } finally {
    setLoading(false);
  }
};

