import React, { useState, useEffect } from 'react';
import { 
  Phone, Users, TrendingUp, Activity, Settings, Grid,
  Zap, Circle, ChevronRight, Plus, Mic, BarChart3, 
  Play, Pause, Upload, Download, Search, Ban, User
} from 'lucide-react';
import axios from 'axios';
import BotPoolManager from './BotPoolManager';
import CampaignManager from './CampaignManager';
import LeadManager from './LeadManager';
import CallHistory from './CallHistory';
import Analytics from './Analytics';
import DNCManager from './DNCManager';
import BatchDial from './BatchDial';
import AppleWrapper from './AppleWrapper';
import ExodusAiLogo from './ExodusAiLogo';
import './AppleComponents.css';
import './DashboardApple.css';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:8000';

function DashboardApple() {
  const [stats, setStats] = useState(null);
  const [activeSection, setActiveSection] = useState('overview');
  const [bots, setBots] = useState([]);
  const [campaigns, setCampaigns] = useState([]);
  const [showModal, setShowModal] = useState(null);
  const [targetBots, setTargetBots] = useState(0);

  useEffect(() => {
    fetchData();
    const interval = setInterval(fetchData, 5000);
    return () => clearInterval(interval);
  }, []);

  const fetchData = async () => {
    try {
      const [statsRes, botsRes, campaignsRes] = await Promise.all([
        axios.get(`${API_URL}/stats`),
        axios.get(`${API_URL}/bots/status`),
        axios.get(`${API_URL}/campaigns`)
      ]);

      // Adapt old API format to new dashboard format
      const adaptedStats = {
        active_calls: statsRes.data.activeCalls || 0,
        today_calls: {
          total_calls: 100, // Mock for now
          answered: Math.round((statsRes.data.connectionRate || 0) * 100 / 100),
        },
        compliance: {
          compliant: (statsRes.data.dropRate || 0) < 3,
          drop_rate_30d: statsRes.data.dropRate || 0
        },
        leads: {
          new: 0,
          total: 0,
          called: 0
        }
      };

      // Adapt bots format - add running field
      const botsArray = botsRes.data.bots || botsRes.data;
      const adaptedBots = botsArray.map(bot => ({
        ...bot,
        running: bot.status?.toLowerCase() === 'idle' || bot.status?.toLowerCase() === 'busy'
      }));

      // Adapt campaigns format - map is_active to status
      const campaignsArray = campaignsRes.data.campaigns || campaignsRes.data;
      const adaptedCampaigns = campaignsArray.map(c => ({
        ...c,
        status: c.is_active ? 'ACTIVE' : 'PAUSED'
      }));

      setStats(adaptedStats);
      setBots(adaptedBots);
      setCampaigns(adaptedCampaigns);
    } catch (error) {
      console.error('Failed to fetch data:', error);
    }
  };

  const activeBots = bots.filter(b => b.running).length;
  const connectionRate = stats?.today_calls?.total_calls > 0 
    ? ((stats.today_calls.answered / stats.today_calls.total_calls) * 100).toFixed(0)
    : 0;

  useEffect(() => {
    setTargetBots(activeBots);
  }, [activeBots]);

  return (
    <div className="dashboard-apple">
      {/* Status Bar - Like iOS */}
      <div className="status-bar">
        <div className="status-left">
          <span className="status-time">{new Date().toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' })}</span>
        </div>
        <div className="status-center">
          <div className="dynamic-island">
            <div className="island-content">
              <Mic className="pulse" size={12} />
              <span>{activeBots} Active</span>
            </div>
          </div>
        </div>
        <div className="status-right">
          <Activity size={14} />
          <div className="battery">
            <div className="battery-fill" style={{ width: '75%' }} />
          </div>
        </div>
      </div>

      {/* Navigation Tabs */}
      <div className="apple-nav-tabs">
        <button 
          className={`apple-tab ${activeSection === 'overview' ? 'active' : ''}`}
          onClick={() => setActiveSection('overview')}
        >
          <Grid size={16} />
          Overview
        </button>
        <button 
          className={`apple-tab ${activeSection === 'bots' ? 'active' : ''}`}
          onClick={() => setActiveSection('bots')}
        >
          <Users size={16} />
          Bots
        </button>
        <button 
          className={`apple-tab ${activeSection === 'campaigns' ? 'active' : ''}`}
          onClick={() => setActiveSection('campaigns')}
        >
          <TrendingUp size={16} />
          Campaigns
        </button>
        <button 
          className={`apple-tab ${activeSection === 'batch' ? 'active' : ''}`}
          onClick={() => setActiveSection('batch')}
        >
          <Zap size={16} />
          Batch Dial
        </button>
        <button 
          className={`apple-tab ${activeSection === 'leads' ? 'active' : ''}`}
          onClick={() => setActiveSection('leads')}
        >
          <User size={16} />
          Leads
        </button>
        <button 
          className={`apple-tab ${activeSection === 'calls' ? 'active' : ''}`}
          onClick={() => setActiveSection('calls')}
        >
          <Phone size={16} />
          Calls
        </button>
        <button 
          className={`apple-tab ${activeSection === 'dnc' ? 'active' : ''}`}
          onClick={() => setActiveSection('dnc')}
        >
          <Ban size={16} />
          DNC
        </button>
        <button 
          className={`apple-tab ${activeSection === 'analytics' ? 'active' : ''}`}
          onClick={() => setActiveSection('analytics')}
        >
          <BarChart3 size={16} />
          Analytics
        </button>
      </div>

      {/* Main Content */}
      <div className="dashboard-content">
        {activeSection === 'overview' ? (
          <>
        {/* Activity Rings with Logo - Like Apple Watch */}
        <div className="activity-rings-container">
          {/* Logo Card - Same size as activity ring cards */}
          <div className="activity-ring-card glass-card" style={{
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            padding: '20px'
          }}>
            <div style={{
              display: 'flex',
              flexDirection: 'row',
              alignItems: 'center',
              justifyContent: 'center',
              gap: '15px',
              width: '100%'
            }}>
              <ExodusAiLogo
                width="120px"
                height="120px"
                showText={false}
                compact={false}
              />
              <div style={{textAlign: 'left'}}>
                <div style={{
                  fontSize: '28px',
                  fontWeight: '700',
                  color: '#FFFFFF',
                  letterSpacing: '2px'
                }}>
                  EXODUS
                </div>
                <div style={{
                  fontSize: '13px',
                  fontWeight: '500',
                  color: '#00B2FF',
                  letterSpacing: '3px',
                  marginTop: '2px'
                }}>
                  PREDICTIVE AI
                </div>
              </div>
            </div>
          </div>

          {/* AI Avatar Card */}
          <div className="activity-ring-card glass-card" style={{
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            padding: '20px',
            overflow: 'hidden',
            position: 'relative'
          }}>
            <div style={{
              width: '160px',
              height: '160px',
              borderRadius: '50%',
              overflow: 'hidden',
              border: '4px solid rgba(0, 178, 255, 0.5)',
              boxShadow: '0 0 30px rgba(0, 178, 255, 0.6), inset 0 0 20px rgba(0, 178, 255, 0.2)',
              background: 'linear-gradient(135deg, rgba(0, 178, 255, 0.2), rgba(255, 107, 0, 0.2))'
            }}>
              <img
                src="/ai-avatar.jpg"
                alt="AI Avatar"
                style={{
                  width: '100%',
                  height: '100%',
                  objectFit: 'cover'
                }}
                onError={(e) => {
                  e.target.style.display = 'none';
                  e.target.parentElement.innerHTML = '<div style="width:100%;height:100%;display:flex;align-items:center;justify-content:center;font-size:48px;">🤖</div>';
                }}
              />
            </div>
          </div>

          <div className="activity-ring-card glass-card">
            <div className="ring-wrapper">
              <svg width="140" height="140" className="activity-ring">
                <circle cx="70" cy="70" r="60" className="ring-bg" />
                <circle 
                  cx="70" cy="70" r="60" 
                  className="ring-fill ring-calls"
                  strokeDasharray={`${(stats?.today_calls?.total_calls || 0) * 3.77} 377`}
                />
                <circle cx="70" cy="70" r="48" className="ring-bg" />
                <circle 
                  cx="70" cy="70" r="48" 
                  className="ring-fill ring-success"
                  strokeDasharray={`${connectionRate * 3.02} 302`}
                />
                <circle cx="70" cy="70" r="36" className="ring-bg" />
                <circle 
                  cx="70" cy="70" r="36" 
                  className="ring-fill ring-active"
                  strokeDasharray={`${(activeBots / 20) * 226} 226`}
                />
              </svg>
              <div className="ring-center">
                <div className="ring-value">{stats?.today_calls?.total_calls || 0}</div>
                <div className="ring-label">CALLS</div>
              </div>
            </div>
            <div className="ring-legend">
              <div className="legend-item">
                <span className="legend-dot calls" />
                <span>Total Calls</span>
                <span className="legend-value">{stats?.today_calls?.total_calls || 0}</span>
              </div>
              <div className="legend-item">
                <span className="legend-dot success" />
                <span>Success Rate</span>
                <span className="legend-value">{connectionRate}%</span>
              </div>
              <div className="legend-item">
                <span className="legend-dot active" />
                <span>Active Bots</span>
                <span className="legend-value">{activeBots}/20</span>
              </div>
            </div>
          </div>
        </div>

        {/* Control Center Grid - Like iOS Control Center */}
        <div className="control-center">
          <div className="control-grid">
            {/* Bot Control */}
            <div className="control-tile large glass-card" onClick={() => setActiveSection('bots')}>
              <div className="control-icon">
                <Users size={24} />
              </div>
              <div className="control-info">
                <div className="control-value">{activeBots}</div>
                <div className="control-label">Active Bots</div>
              </div>
              <div className="control-slider">
                <input 
                  type="range" 
                  min="0" 
                  max="20" 
                  value={targetBots}
                  className="ios-slider"
                  onClick={(e) => e.stopPropagation()}
                  onChange={(e) => setTargetBots(parseInt(e.target.value))}
                  onMouseUp={() => adjustBots(targetBots)}
                  onTouchEnd={() => adjustBots(targetBots)}
                />
              </div>
            </div>

            {/* Campaigns */}
            <div className="control-tile medium glass-card" onClick={() => setActiveSection('campaigns')}>
              <div className="tile-header">
                <TrendingUp size={20} />
                <span className="tile-badge">{campaigns.filter(c => c.status === 'ACTIVE').length}</span>
              </div>
              <div className="tile-content">
                <div className="tile-value">{campaigns.length}</div>
                <div className="tile-label">Campaigns</div>
              </div>
            </div>

            {/* Connection Rate */}
            <div className="control-tile medium glass-card">
              <div className="tile-header">
                <Zap size={20} />
              </div>
              <div className="tile-content">
                <div className="tile-value">{connectionRate}%</div>
                <div className="tile-label">Connection</div>
              </div>
              <div className="mini-chart">
                {[...Array(10)].map((_, i) => (
                  <div 
                    key={i}
                    className="chart-bar"
                    style={{ height: `${Math.random() * 100}%` }}
                  />
                ))}
              </div>
            </div>

            {/* Compliance Status */}
            <div className="control-tile small glass-card">
              <div className={`compliance-indicator ${stats?.compliance?.compliant ? 'compliant' : 'warning'}`}>
                <Circle size={16} fill="currentColor" />
              </div>
              <div className="tile-label">TCPA</div>
              <div className="tile-micro">{stats?.compliance?.drop_rate_30d || 0}%</div>
            </div>

            {/* Quick Actions */}
            <div 
              className="control-tile small glass-card action-tile"
              onClick={() => setActiveSection('calls')}
            >
              <Phone size={20} />
              <div className="tile-label">Call</div>
            </div>

            <div 
              className="control-tile small glass-card action-tile"
              onClick={() => {
                setActiveSection('leads');
                setShowModal('add-lead');
              }}
            >
              <Plus size={20} />
              <div className="tile-label">Lead</div>
            </div>

            <div 
              className="control-tile small glass-card action-tile"
              onClick={() => setActiveSection('analytics')}
            >
              <BarChart3 size={20} />
              <div className="tile-label">Stats</div>
            </div>
          </div>
        </div>

        {/* Live Activity Cards - Like iOS Live Activities */}
        <div className="live-activities">
          <h3 className="section-title">Live Activities</h3>
          <div className="activity-list">
            {bots.filter(b => b.status?.toLowerCase() === 'busy').slice(0, 3).map(bot => (
              <div key={bot.port} className="activity-card glass-card">
                <div className="activity-icon pulse-container">
                  <div className="pulse-ring" />
                  <Phone size={16} />
                </div>
                <div className="activity-details">
                  <div className="activity-title">Bot {bot.port}</div>
                  <div className="activity-status">In call • 2:34</div>
                </div>
                <div className="activity-graph">
                  <div className="waveform">
                    {[...Array(20)].map((_, i) => (
                      <div 
                        key={i}
                        className="wave-bar"
                        style={{ height: `${Math.random() * 100}%` }}
                      />
                    ))}
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Quick Stats - Like iOS Widgets */}
        <div className="widget-grid">
          <div className="widget glass-card">
            <div className="widget-header">
              <Phone size={16} />
              <span>Today's Calls</span>
            </div>
            <div className="widget-value">{stats?.today_calls?.total_calls || 0}</div>
            <div className="widget-chart">
              <div className="spark-line">
                {[...Array(7)].map((_, i) => (
                  <div 
                    key={i}
                    className="spark-bar"
                    style={{ height: `${Math.random() * 100}%` }}
                  />
                ))}
              </div>
            </div>
          </div>

          <div className="widget glass-card">
            <div className="widget-header">
              <Users size={16} />
              <span>New Leads</span>
            </div>
            <div className="widget-value">{stats?.leads?.new || 0}</div>
            <div className="widget-progress">
              <div className="progress-bar">
                <div className="progress-fill" style={{ width: '65%' }} />
              </div>
            </div>
          </div>

          <div className="widget glass-card">
            <div className="widget-header">
              <TrendingUp size={16} />
              <span>Conversion</span>
            </div>
            <div className="widget-value">
              {stats?.leads?.called && stats?.leads?.total 
                ? Math.round((stats.leads.called / stats.leads.total) * 100)
                : 0}%
            </div>
            <div className="widget-trend up">
              <TrendingUp size={12} />
              <span>+12%</span>
            </div>
          </div>

          <div className="widget glass-card">
            <div className="widget-header">
              <Activity size={16} />
              <span>Avg Duration</span>
            </div>
            <div className="widget-value">
              {Math.round(stats?.today_calls?.avg_duration || 0)}s
            </div>
            <div className="widget-subtitle">Per call</div>
          </div>
        </div>
          </>
        ) : activeSection === 'bots' ? (
          <AppleWrapper>
            <BotPoolManager apiUrl={API_URL} />
          </AppleWrapper>
        ) : activeSection === 'campaigns' ? (
          <AppleWrapper>
            <CampaignManager apiUrl={API_URL} />
          </AppleWrapper>
        ) : activeSection === 'batch' ? (
          <AppleWrapper>
            <BatchDial apiUrl={API_URL} />
          </AppleWrapper>
        ) : activeSection === 'leads' ? (
          <AppleWrapper>
            <LeadManager apiUrl={API_URL} />
          </AppleWrapper>
        ) : activeSection === 'calls' ? (
          <AppleWrapper>
            <CallHistory apiUrl={API_URL} />
          </AppleWrapper>
        ) : activeSection === 'dnc' ? (
          <AppleWrapper>
            <DNCManager apiUrl={API_URL} />
          </AppleWrapper>
        ) : activeSection === 'analytics' ? (
          <AppleWrapper>
            <Analytics apiUrl={API_URL} />
          </AppleWrapper>
        ) : null}
      </div>

      {/* Floating Action Button - iOS Style */}
      <button 
        className="fab"
        onClick={() => {
          if (activeSection === 'campaigns') {
            setShowModal('add-campaign');
          } else if (activeSection === 'leads') {
            setShowModal('add-lead');
          } else if (activeSection === 'dnc') {
            setShowModal('add-dnc');
          } else {
            setActiveSection('overview');
          }
        }}
      >
        <Plus size={24} />
      </button>

      {/* Quick Action Modals */}
      {showModal === 'add-campaign' && (
        <AddCampaignModal 
          onClose={() => setShowModal(null)}
          onAdd={async (campaign) => {
            try {
              await axios.post(`${API_URL}/campaigns`, campaign);
              setShowModal(null);
              fetchData();
            } catch (error) {
              alert('Failed to create campaign');
            }
          }}
        />
      )}

      {showModal === 'add-lead' && (
        <AddLeadModal 
          onClose={() => setShowModal(null)}
          campaigns={campaigns}
          onAdd={async (lead) => {
            try {
              await axios.post(`${API_URL}/leads`, lead);
              setShowModal(null);
              fetchData();
            } catch (error) {
              alert('Failed to add lead');
            }
          }}
        />
      )}
    </div>
  );

  async function adjustBots(value) {
    try {
      await axios.post(`${API_URL}/bots/adjust-pool`, {
        target_count: parseInt(value)
      });
      fetchData();
    } catch (error) {
      console.error('Failed to adjust bots:', error);
    }
  }
}

// Modal Components
function AddCampaignModal({ onClose, onAdd }) {
