              alignItems: 'center',
              justifyContent: 'center',
              gap: '15px',
              width: '100%'
            }}>
              <ExodusAiLogo
                width="120px"
                height="120px"
                showText={false}
                compact={false}
              />
              <div style={{textAlign: 'left'}}>
                <div style={{
                  fontSize: '28px',
                  fontWeight: '700',
                  color: '#FFFFFF',
                  letterSpacing: '2px'
                }}>
                  EXODUS
                </div>
                <div style={{
                  fontSize: '13px',
                  fontWeight: '500',
                  color: '#00B2FF',
                  letterSpacing: '3px',
                  marginTop: '2px'
                }}>
                  PREDICTIVE AI
                </div>
              </div>
            </div>
          </div>

          {/* AI Avatar Card */}
          <div className="activity-ring-card glass-card" style={{
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            padding: '20px',
            overflow: 'hidden',
            position: 'relative'
          }}>
            <div style={{
              width: '160px',
              height: '160px',
              borderRadius: '50%',
              overflow: 'hidden',
              border: '4px solid rgba(0, 178, 255, 0.5)',
              boxShadow: '0 0 30px rgba(0, 178, 255, 0.6), inset 0 0 20px rgba(0, 178, 255, 0.2)',
              background: 'linear-gradient(135deg, rgba(0, 178, 255, 0.2), rgba(255, 107, 0, 0.2))'
            }}>
              <img
                src="/ai-avatar.jpg"
                alt="AI Avatar"
                style={{
                  width: '100%',
