                <span className="legend-value">{activeBots}/20</span>
              </div>
            </div>
          </div>
        </div>

        {/* Control Center Grid - Like iOS Control Center */}
        <div className="control-center">
          <div className="control-grid">
            {/* Bot Control */}
            <div className="control-tile large glass-card" onClick={() => setActiveSection('bots')}>
              <div className="control-icon">
                <Users size={24} />
              </div>
              <div className="control-info">
                <div className="control-value">{activeBots}</div>
                <div className="control-label">Active Bots</div>
              </div>
              <div className="control-slider">
                <input 
                  type="range" 
                  min="0" 
                  max="20" 
                  value={targetBots}
                  className="ios-slider"
                  onClick={(e) => e.stopPropagation()}
                  onChange={(e) => setTargetBots(parseInt(e.target.value))}
                  onMouseUp={() => adjustBots(targetBots)}
                  onTouchEnd={() => adjustBots(targetBots)}
                />
              </div>
            </div>

            {/* Campaigns */}
            <div className="control-tile medium glass-card" onClick={() => setActiveSection('campaigns')}>
              <div className="tile-header">
                <TrendingUp size={20} />
                <span className="tile-badge">{campaigns.filter(c => c.status === 'ACTIVE').length}</span>
              </div>
              <div className="tile-content">
                <div className="tile-value">{campaigns.length}</div>
                <div className="tile-label">Campaigns</div>
              </div>
            </div>

            {/* Connection Rate */}
